        }
        _gpuProbeActive = false;
        return;
      }

      final boundaryContext = _fractalKeyA.currentContext;
      if (boundaryContext == null) {
        _log.warn('gpu',
            'Health check skipped: no boundary context (renderer not mounted?)');
        if (kDebugMode) {
          debugPrint(
