        }
        _gpuProbeActive = false;
        return;
      }
      final renderObject = boundaryContext.findRenderObject();
      if (renderObject is! RenderRepaintBoundary) {
        _log.warn('gpu', 'Health check skipped: no RenderRepaintBoundary');
